#include<bits/stdc++.h>
using namespace std;
int f(string s){
	int a[135]={0},maxn=0;
	for(int i=0;i<s.size();i++)a[int(s[i])]+=1;
	for(int i=0;i<135;i++)maxn=max(a[i],maxn);
	return maxn;
}
int main(void){
	string s,z;
	int ans=0;
	cin>>s;
	for(int i=0;i<s.size()-1;i++){
		for(int j=i+1;j<s.size();j++){
			z="";
			for(int k=i;k<=j;k++)z+=s[k];
			if(f(z)<=int(z.size()/2)){
				ans++;
			}
		}
	}
	cout<<ans;
    return false;
}
